import{_ as o,C as n,o as i,c as l,j as t,a as s,G as d,ag as r}from"./chunks/framework.Ds56KWXN.js";const v=JSON.parse('{"title":"Package vs Individual Installs","description":"Understand the difference between the Health Checker complete package and individual extension ZIPs. Learn which to download and when individual installs make sense.","frontmatter":{"description":"Understand the difference between the Health Checker complete package and individual extension ZIPs. Learn which to download and when individual installs make sense.","head":[["meta",{"property":"og:title","content":"Package vs Individual Installs | Health Checker for Joomla"}],["meta",{"property":"og:description","content":"Understand the difference between the Health Checker complete package and individual extension ZIPs. Learn which to download and when individual installs make sense."}],["meta",{"property":"og:url","content":"https://www.joomlahealthchecker.com/docs/packages-vs-individual"}],["meta",{"name":"twitter:title","content":"Package vs Individual Installs | Health Checker for Joomla"}],["meta",{"name":"twitter:description","content":"Understand the difference between the Health Checker complete package and individual extension ZIPs. Learn which to download and when individual installs make sense."}],["meta",{"name":"twitter:url","content":"https://www.joomlahealthchecker.com/docs/packages-vs-individual"}]]},"headers":[],"relativePath":"packages-vs-individual.md","filePath":"packages-vs-individual.md"}'),h={name:"packages-vs-individual.md"};function c(p,e,u,g,m,k){const a=n("CopyOrDownloadAsMarkdownButtons");return i(),l("div",null,[e[0]||(e[0]=t("div",{style:{display:"none"},hidden:"true","aria-hidden":"true"},"Are you an LLM? You can read better optimized documentation at /docs/packages-vs-individual.md for this page in Markdown format",-1)),e[1]||(e[1]=t("h1",{id:"package-vs-individual-installs",tabindex:"-1"},[s("Package vs Individual Installs "),t("a",{class:"header-anchor",href:"#package-vs-individual-installs","aria-label":'Permalink to "Package vs Individual Installs"'},"​")],-1)),d(a),e[2]||(e[2]=r('<p>When you visit the <a href="https://github.com/mySites-guru/HealthCheckerForJoomla/releases" target="_blank" rel="noreferrer">releases page</a>, you&#39;ll see several ZIP files. This page explains what each one is and which one you should download.</p><h2 id="the-complete-package-recommended" tabindex="-1">The Complete Package (recommended) <a class="header-anchor" href="#the-complete-package-recommended" aria-label="Permalink to &quot;The Complete Package (recommended)&quot;">​</a></h2><p><strong><code>pkg_healthchecker-x.x.x.zip</code></strong> is the file most people should download.</p><p>This is a Joomla <a href="https://docs.joomla.org/Extension_types_(general_definitions)" target="_blank" rel="noreferrer">package</a> — a single ZIP that bundles everything together:</p><table tabindex="0"><thead><tr><th>Extension</th><th>Type</th><th>Purpose</th></tr></thead><tbody><tr><td><code>com_healthchecker</code></td><td>Component</td><td>The main application — admin UI, report page, event system</td></tr><tr><td><code>plg_healthchecker_core</code></td><td>Plugin</td><td>All 130+ built-in health checks</td></tr><tr><td><code>mod_healthchecker</code></td><td>Module</td><td>Dashboard widget showing health summary</td></tr><tr><td><code>plg_healthchecker_akeebabackup</code></td><td>Plugin</td><td>Akeeba Backup integration checks (optional)</td></tr><tr><td><code>plg_healthchecker_akeebaadmintools</code></td><td>Plugin</td><td>Akeeba Admin Tools integration checks (optional)</td></tr><tr><td><code>plg_healthchecker_mysitesguru</code></td><td>Plugin</td><td>mySites.guru API integration (optional)</td></tr><tr><td><code>plg_healthchecker_example</code></td><td>Plugin</td><td>Example plugin for developers (optional)</td></tr></tbody></table><p>One install, everything works. The package installs all pieces in the right order and handles dependencies for you.</p><h3 id="updating-with-the-package" tabindex="-1">Updating with the package <a class="header-anchor" href="#updating-with-the-package" aria-label="Permalink to &quot;Updating with the package&quot;">​</a></h3><p>When you update the package ZIP, Joomla updates <strong>all</strong> the extensions inside it at once. If you see individual plugin updates available in Joomla Update or tools like Akeeba Panopticon, you only need to update the package — it covers everything.</p><h2 id="the-individual-zips" tabindex="-1">The Individual ZIPs <a class="header-anchor" href="#the-individual-zips" aria-label="Permalink to &quot;The Individual ZIPs&quot;">​</a></h2><p>The remaining files on the releases page are the individual extensions that make up the package:</p><ul><li><code>com_healthchecker-x.x.x.zip</code> — Component only</li><li><code>plg_healthchecker_core-x.x.x.zip</code> — Core checks plugin only</li><li><code>mod_healthchecker-x.x.x.zip</code> — Dashboard module only</li><li><code>plg_healthchecker_akeebabackup-x.x.x.zip</code> — Akeeba Backup plugin only</li><li><code>plg_healthchecker_akeebaadmintools-x.x.x.zip</code> — Admin Tools plugin only</li><li><code>plg_healthchecker_mysitesguru-x.x.x.zip</code> — mySites.guru plugin only</li><li><code>plg_healthchecker_example-x.x.x.zip</code> — Example developer plugin only</li></ul><h3 id="why-individual-zips-exist" tabindex="-1">Why individual ZIPs exist <a class="header-anchor" href="#why-individual-zips-exist" aria-label="Permalink to &quot;Why individual ZIPs exist&quot;">​</a></h3><p>Individual ZIPs are provided for situations where the complete package isn&#39;t ideal:</p><ul><li><strong>Selective installation</strong> — You only want specific plugins and don&#39;t want the optional ones installed at all</li><li><strong>Independent updates</strong> — A fix is released for just one plugin and you want to update only that piece</li><li><strong>Third-party distribution</strong> — Developers building their own check plugins can ship them as standalone ZIPs</li></ul><h3 id="dependencies-matter" tabindex="-1">Dependencies matter <a class="header-anchor" href="#dependencies-matter" aria-label="Permalink to &quot;Dependencies matter&quot;">​</a></h3><p>The individual pieces depend on each other. The plugins and module all require the component (<code>com_healthchecker</code>) to be installed first. If you install a plugin ZIP without the component, Joomla will throw errors because the plugin tries to use component classes that don&#39;t exist.</p><p><strong>Minimum required for Health Checker to work:</strong></p><ol><li><code>com_healthchecker</code> (component) — must be installed first</li><li><code>plg_healthchecker_core</code> (core plugin) — must be installed and <strong>enabled</strong></li></ol><p>Without both of these, Health Checker won&#39;t function.</p><h2 id="which-should-i-use" tabindex="-1">Which should I use? <a class="header-anchor" href="#which-should-i-use" aria-label="Permalink to &quot;Which should I use?&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scenario</th><th>Recommendation</th></tr></thead><tbody><tr><td>First time installing</td><td>Complete package (<code>pkg_healthchecker</code>)</td></tr><tr><td>Updating an existing install</td><td>Complete package (<code>pkg_healthchecker</code>)</td></tr><tr><td>You don&#39;t use Akeeba extensions and don&#39;t want those plugins present</td><td>Individual ZIPs (component + core + module)</td></tr><tr><td>You manage updates via <a href="https://mysites.guru" target="_blank" rel="noreferrer">mySites.guru</a> and want full control over which plugins are enabled</td><td>Individual ZIPs — see note below</td></tr><tr><td>You&#39;re a developer building a custom check plugin</td><td>Your plugin ZIP only (assumes component is already installed)</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Managing plugin state with mySites.guru or other automation tools</p><p>When installed via the complete package, all bundled plugins are enabled on first install. If you disable optional plugins (like the example or mySites.guru plugins) and later update via the package, the plugins stay in their current enabled/disabled state — the package respects your choices on update.</p><p>If you still prefer to control exactly which plugins exist on your site, install the individual ZIPs for just the parts you want.</p></div><h2 id="switching-from-package-to-individual-installs" tabindex="-1">Switching from package to individual installs <a class="header-anchor" href="#switching-from-package-to-individual-installs" aria-label="Permalink to &quot;Switching from package to individual installs&quot;">​</a></h2><p>If you originally installed the complete package but want to switch to individual management:</p><ol><li><strong>Uninstall the package</strong> — Go to <strong>System &gt; Manage &gt; Extensions</strong>, find <code>Health Checker for Joomla</code> (type: Package), and uninstall it. This removes everything.</li><li><strong>Install the component</strong> — <code>com_healthchecker-x.x.x.zip</code></li><li><strong>Install the core plugin</strong> — <code>plg_healthchecker_core-x.x.x.zip</code> and enable it</li><li><strong>Install the dashboard module</strong> — <code>mod_healthchecker-x.x.x.zip</code></li><li><strong>Install any optional plugins you want</strong> — only the ones you need</li></ol><p>From this point on, each extension updates independently and you won&#39;t have unwanted plugins on your site.</p><h2 id="switching-from-individual-installs-to-the-package" tabindex="-1">Switching from individual installs to the package <a class="header-anchor" href="#switching-from-individual-installs-to-the-package" aria-label="Permalink to &quot;Switching from individual installs to the package&quot;">​</a></h2><p>If you installed the pieces individually and want to switch to the package for simpler updates:</p><ol><li>Install <code>pkg_healthchecker-x.x.x.zip</code> through <strong>System &gt; Install &gt; Extensions</strong></li><li>Joomla will detect the existing extensions and upgrade them in place</li><li>Any plugins you didn&#39;t previously have will be installed and enabled</li></ol><h2 id="common-mistakes" tabindex="-1">Common mistakes <a class="header-anchor" href="#common-mistakes" aria-label="Permalink to &quot;Common mistakes&quot;">​</a></h2><h3 id="installing-a-plugin-without-the-component" tabindex="-1">Installing a plugin without the component <a class="header-anchor" href="#installing-a-plugin-without-the-component" aria-label="Permalink to &quot;Installing a plugin without the component&quot;">​</a></h3><p><strong>Symptom</strong>: Fatal error or white screen after installing a plugin ZIP.</p><p><strong>Cause</strong>: The plugin needs classes from <code>com_healthchecker</code> which isn&#39;t installed.</p><p><strong>Fix</strong>: Install the complete package, or install <code>com_healthchecker</code> first, then the plugin.</p><h3 id="installing-the-component-without-the-core-plugin" tabindex="-1">Installing the component without the core plugin <a class="header-anchor" href="#installing-the-component-without-the-core-plugin" aria-label="Permalink to &quot;Installing the component without the core plugin&quot;">​</a></h3><p><strong>Symptom</strong>: Health Checker opens but shows no checks when you run it.</p><p><strong>Cause</strong>: The component provides the framework, but the actual health checks live in the core plugin.</p><p><strong>Fix</strong>: Install and enable <code>plg_healthchecker_core</code>.</p><h3 id="downloading-the-wrong-zip-from-the-releases-page" tabindex="-1">Downloading the wrong ZIP from the releases page <a class="header-anchor" href="#downloading-the-wrong-zip-from-the-releases-page" aria-label="Permalink to &quot;Downloading the wrong ZIP from the releases page&quot;">​</a></h3><p><strong>Symptom</strong>: After installation, Health Checker doesn&#39;t work or is missing pieces.</p><p><strong>Cause</strong>: You downloaded one of the individual ZIPs instead of the complete package.</p><p><strong>Fix</strong>: Go back to the <a href="https://github.com/mySites-guru/HealthCheckerForJoomla/releases" target="_blank" rel="noreferrer">releases page</a> and download <code>pkg_healthchecker-x.x.x.zip</code> — the file with <code>pkg_</code> at the start of the name.</p><h2 id="how-joomla-extensions-work" tabindex="-1">How Joomla extensions work <a class="header-anchor" href="#how-joomla-extensions-work" aria-label="Permalink to &quot;How Joomla extensions work&quot;">​</a></h2><p>For context, Joomla has several extension types:</p><ul><li><strong>Components</strong> are the main applications. They provide the admin pages, menus, and core logic. Health Checker&#39;s component handles the report page, the event system, and the UI.</li><li><strong>Plugins</strong> are event handlers. They respond to events fired by components. Health Checker&#39;s plugins provide the actual health checks — the core plugin registers 130+ checks when the component fires its <code>CollectChecksEvent</code>.</li><li><strong>Modules</strong> are small widgets that display information. Health Checker&#39;s module shows a health summary on the admin dashboard.</li><li><strong>Packages</strong> are bundles that install multiple extensions together. They don&#39;t add any functionality themselves — they&#39;re just a convenient way to distribute related extensions as a single download.</li></ul><p>This modular design is why Health Checker is split into multiple pieces rather than being one monolithic extension. It allows third-party developers to <a href="/docs/developers/">create their own check plugins</a> without modifying the core.</p>',46))])}const x=o(h,[["render",c]]);export{v as __pageData,x as default};
